from flask import Flask, request, send_file, jsonify, abort
from pathlib import Path
import os

app = Flask(__name__)

# Base directory where files are stored
BASE_DIR = Path('/path/to/uploaded/files').resolve()

# Example mapping from file IDs to file paths
file_id_to_path = {
    "file1": "documents/report.pdf",
    "file2": "images/photo.jpg",
    # Add more mappings as needed
}

def get_full_path(user_path):
    try:
        # Resolve the full path and ensure it's within the base directory
        full_path = (BASE_DIR / user_path).resolve()
        if not full_path.is_relative_to(BASE_DIR):
            raise ValueError("Path traversal detected")
        return full_path
    except Exception as e:
        abort(400, str(e))

@app.route('/list', methods=['GET'])
def list_directory():
    dir_id = request.args.get('dir_id')
    if dir_id not in file_id_to_path:
        abort(404, "Directory not found")
    user_path = file_id_to_path[dir_id]
    full_path = get_full_path(user_path)
    if not full_path.is_dir():
        abort(400, "Not a directory")
    files = os.listdir(full_path)
    return jsonify(files)

@app.route('/download', methods=['GET'])
def download_file():
    file_id = request.args.get('file_id')
    if file_id not in file_id_to_path:
        abort(404, "File not found")
    user_path = file_id_to_path[file_id]
    full_path = get_full_path(user_path)
    if not full_path.is_file():
        abort(400, "Not a file")
    return send_file(full_path)

@app.route('/info', methods=['GET'])
def get_file_info():
    file_id = request.args.get('file_id')
    if file_id not in file_id_to_path:
        abort(404, "File not found")
    user_path = file_id_to_path[file_id]
    full_path = get_full_path(user_path)
    if not full_path.exists():
        abort(400, "File does not exist")
    file_info = {
        "name": full_path.name,
        "size": full_path.stat().st_size,
        "modified": full_path.stat().st_mtime
    }
    return jsonify(file_info)

if __name__ == '__main__':
    app.run(debug=True)